"use client";
import { useState } from "react";
import Header from "@/components/Header";
import AboutModal from "@/components/AboutModal";

export default function CatalogPage() {
    const [showAbout, setShowAbout] = useState(false);
    const [search, setSearch] = useState("");
    const [category, setCategory] = useState("all");

    const books = [
        { id: 1, title: "Мастер и Маргарита", author: "М. Булгаков", year: 1967, category: "fiction", available: true },
        { id: 2, title: "1984", author: "Дж. Оруэлл", year: 1949, category: "fiction", available: false },
        { id: 3, title: "Основы JavaScript", author: "Д. Фланаган", year: 2020, category: "tech", available: true },
        { id: 4, title: "Чистый код", author: "Р. Мартин", year: 2019, category: "tech", available: true },
        { id: 5, title: "Война и мир", author: "Л. Толстой", year: 1869, category: "fiction", available: true },
        { id: 6, title: "История России", author: "Н. Карамзин", year: 1818, category: "history", available: false },
    ];

    const categories = [
        { id: "all", label: "📚 Все книги" },
        { id: "fiction", label: "📖 Художественная" },
        { id: "tech", label: "💻 Технологии" },
        { id: "science", label: "🔬 Научная" },
        { id: "history", label: "🏛️ История" },
        { id: "kids", label: "🧸 Детская" },
    ];

    const filtered = books.filter(b => {
        const matchesSearch = b.title.toLowerCase().includes(search.toLowerCase()) ||
            b.author.toLowerCase().includes(search.toLowerCase());
        const matchesCategory = category === "all" || b.category === category;
        return matchesSearch && matchesCategory;
    });

    return (
        <>
            <Header onOpenAbout={() => setShowAbout(true)} />

            <div className="container">
                <div className="catalog-header">
                    <h1>📚 Электронный фонд</h1>
                    <p className="subtitle">Каталог изданий — более 2 400 книг в вашей библиотеке</p>

                    <div className="search-bar">
                        <input
                            type="text"
                            placeholder="🔍 Поиск по названию или автору..."
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                        />
                    </div>

                    <div className="categories-filter">
                        {categories.map(cat => (
                            <button
                                key={cat.id}
                                className={`filter-btn ${category === cat.id ? "active" : ""}`}
                                onClick={() => setCategory(cat.id)}
                            >
                                {cat.label}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="books-grid">
                    {filtered.map(book => (
                        <div key={book.id} className="book-card">
                            <div className="book-cover">
                                <span className="book-initial">{book.title.charAt(0)}</span>
                            </div>
                            <div className="book-info">
                                <h4>{book.title}</h4>
                                <p className="author">{book.author}</p>
                                <p className="year">📅 {book.year}</p>
                                <span className={`availability ${book.available ? "available" : "unavailable"}`}>
                  {book.available ? "✓ В наличии" : "✗ На бронировании"}
                </span>
                                <button className="btn-action" disabled={!book.available}>
                                    {book.available ? "📖 Читать" : "🔔 Уведомить"}
                                </button>
                            </div>
                        </div>
                    ))}
                </div>

                {filtered.length === 0 && (
                    <div className="empty-results">
                        <p>🔍 Ничего не найдено по вашему запросу</p>
                        <button className="btn-reset" onClick={() => { setSearch(""); setCategory("all"); }}>
                            Сбросить фильтры
                        </button>
                    </div>
                )}
            </div>

            {showAbout && <AboutModal onClose={() => setShowAbout(false)} />}
        </>
    );
}